class SessionStore {
  constructor() {
    this.sessions = {};  // in-memory
  }
  set(userId, data) {
    this.sessions[userId] = { data, lastAccess: Date.now() };
  }
  get(userId) {
    return this.sessions[userId]?.data;
  }
}
// Used in production with 3 load-balanced app servers
